VALUES
  ('heelevel3-29a002de-moex-00031', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-e733516d', 'sub-heelevel3-29a002de-02', NULL, 'essay', '警方為調查甲涉犯販毒罪情形，於依法取得法院核發令狀後，使用Ｍ化
車對甲租用之住宅進行調查蒐證，惟未取得販毒罪之罪證資料。如於使
用Ｍ化車過程中，發現甲另涉犯擄人勒贖罪之證據資料，並於實施期間
屆滿後第三十五日補行陳報法院，則此項涉犯擄人勒贖罪之證據，嗣後
於該擄人勒贖案審判中有無證據能力？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "b919d2e5a3b5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0911", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00032', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'essay', '甲向中古錶商丙表示，授權於 16歲之乙，向丙洽談購買丙所有之中古錶
事宜。其後甲對乙表示撤回代理權，但未通知丙，致使丙信賴乙為甲之
代理人，而與其洽談中古錶之買賣契約。丙見乙年幼可欺，明知其所有
的中古錶中僅有 A 錶為仿冒品，仍謊稱 A 錶為真品並宣稱 A 錶較其所
有的其他中古錶保值，乙因而遭丙詐欺而與其簽訂 A錶買賣契約。試附
理由說明該買賣契約之效力為何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00033', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'essay', '40歲的甲女離婚後，與30歲的乙男結婚。甲女不想再生育，也希望乙能
對自己與前夫丁所生的小孩丙視如己出，遂要求乙收養丙。丙已經滿 13
歲，剛上國中正處於叛逆期。乙為了表明自己照顧丙與融入新家庭的誠心，
同意收養丙。試從民法所定收養的要件，分析乙可否收養丙？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00034', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲與乙為同一棟社區之住戶，甲住8樓，乙住7樓，甲生性愛熱鬧，常常邀約親朋好友到家作客， 並大聲喧嘩，甚至已半夜時分仍在家中高歌作樂。下列敘述，何者錯誤？', '["在他人居住區域，發出超越一般人社會生活所能忍受之噪音，屬不法侵害他人居住安寧之人格 利益", "人格利益至高無上，不容侵犯，只要遭受侵害，不問程度如何，被害人均得依民法第195條第 1項有關人格及身分法益侵害規定，請求賠償相當之金額", "如果長期、持續性噪音，已使人因此無法入眠，健康受損，可能構成健康權之侵害", "健康權屬於特別人格權，若受侵害，被害人得請求非財產上之金錢賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00035', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲將A地出賣於乙，並辦理所有權移轉登記。下列關於所有權移轉之敘述，何者錯誤？', '["應以書面為之", "非經登記，不生效力", "非經移轉占有，不生效力", "此移轉行為係法律行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00036', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '父親甲贈與未成年子女乙一棟房屋，由甲代理乙受領，其效力如何？', '["無效", "有效", "效力未定", "得撤銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00037', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '民法中關於權利主體「自然人」之規定，下列敘述，何者正確？', '["某藝人以「小香瓜」為藝名，因其非真名，不受民法有關姓名權規定之保護", "甲與乙同時遇難，不能證明死亡先後時，視為同時死亡", "丙因失蹤多時生死不明，被妻子依法聲請法院宣告其死亡。但丙實則仍生存中，卻因已受死亡 宣告，所以權利能力及行為能力均為消滅", "丁開車闖紅燈撞上正在過馬路之孕婦戊，致其胎兒受傷。戊為胎兒之法定代理人，固得代為受 領丁給付之賠償金，但若嗣後胎兒死產，該受領之賠償金應返還丁"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00038', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲依民法規定發起設立A學術性社團法人，並將其主事務所設於臺中市。依民法規定，A法人應 向何主管機關登記，始得成立？', '["臺中市政府", "臺中地方法院", "內政部", "教育部"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00039', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲80歲，罹輕度失智症，配偶已歿，有子女乙、丙、丁，平日由女兒乙照顧，乙擔心甲因心智缺 陷，而面臨不必要之法律糾紛，遂向法院聲請為甲為輔助宣告，法院經審查對甲為輔助宣告，並 以乙為甲之輔助人。下列甲之行為，何者須先取得輔助人乙之同意？', '["甲與好友相約到餐廳吃飯", "甲在好友A、B偕同下到C公證人處，在A、B、C見證下自書遺囑，就其法定繼承人乙、丙、 丁為遺產分配各得1/2、1/4、1/4", "甲因開車造成D受傷，自行與D成立和解契約，願意理賠D之身體傷害新臺幣（下同）50萬元", "甲自行到某百貨公司購買價錢1萬元之手錶"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00040', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列關於最高限額抵押權之敘述，何者錯誤？', '["債務人或第三人提供其不動產為擔保", "得擔保不確定或概括債權，例如約定擔保債權人與債務人間「現在及將來一切債務及其利息、 遲延利息、違約金、實行抵押權費用」", "得擔保一定範圍內之不特定債權", "所擔保之債權，應受最高額度限制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL)
